extra.modelCss:
/* Form pro (Login/Cadastro) */

:root {
  --bg: #0b0f19;
  --panel: #111827;
  --text: #e5e7eb;
  --muted: #9ca3af;
  --accent: #60a5fa;
  --border: rgba(255, 255, 255, 0.10);
  --danger: #ef4444;
  --success: #22c55e;
  --radius: 14px;
}

.auth {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 16px;
}

.auth-card {
  width: 100%;
  max-width: 460px;
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
}

.auth-inner {
  padding: 18px;
  display: grid;
  gap: 14px;
}

.auth-header {
  display: grid;
  gap: 6px;
}

.muted {
  color: var(--muted);
}

.auth-form {
  display: grid;
  gap: 14px;
}

.field {
  display: grid;
  gap: 6px;
}

.label {
  font-size: 0.875rem;
}

.input {
  width: 100%;
  padding: 10px 12px;
  border: 1px solid var(--border);
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.02);
  color: var(--text);
}

.input:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 2px;
  border-color: rgba(96, 165, 250, 0.60);
}

.help {
  font-size: 0.875rem;
  color: var(--muted);
}

.input-error {
  border-color: var(--danger);
}

.help-error {
  color: var(--danger);
}

.input-success {
  border-color: var(--success);
}

.help-success {
  color: var(--success);
}

.alert {
  padding: 10px 12px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.02);
}

.alert.error {
  border-color: rgba(239, 68, 68, 0.35);
  background: rgba(239, 68, 68, 0.10);
}

.actions {
  display: grid;
  gap: 10px;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 12px;
  border: 1px solid transparent;
  font-weight: 700;
  cursor: pointer;
  transition: transform 150ms ease, opacity 150ms ease;
}

.btn:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

.btn:hover {
  transform: translateY(-1px);
  opacity: 0.95;
}

.btn.primary {
  background: var(--accent);
  color: #0b0f19;
}

.btn.ghost {
  background: transparent;
  color: var(--text);
  border-color: var(--border);
}

.btn:disabled {
  opacity: 0.55;
  cursor: not-allowed;
  transform: none;
}

@media (min-width: 768px) {
  .auth-inner {
    padding: 22px;
  }
}

@media (prefers-reduced-motion: reduce) {
  * {
    transition: none !important;
    animation: none !important;
  }
}
